// Stand-in for @floating-ui: VENDOR-declared types (a real dependency package — the
// library gate refuses records for these unless the #39 trial accepts a perfect extract).
export type Rect = { x: number; y: number; width: number; height: number };
export interface ClientRectObject { x: number; y: number; width: number; height: number; top: number; right: number; bottom: number; left: number }
export interface VirtualElement {
  getBoundingClientRect(): ClientRectObject;
  getClientRects?(): Array<ClientRectObject> | DOMRectList;
  contextElement?: Element;
}
export type Boundary = 'clipping-ancestors' | Element | Array<Element> | Rect;
// a vendor type with an UNMODELLABLE field — must stay refused (trial rejects + rolls back):
export interface Tainted { ok: boolean; bad: symbol | bigint }
